import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Empty / processing fee
  it.todo("empty item list yields premium of 5 G (processing fee only)");

  // Single item base premiums
  it.todo("single sword (plain, newcomer first contract) yields base + first insurance + fee");
  it.todo("single amulet (plain, newcomer first contract)");
  it.todo("single staff (plain, newcomer first contract)");
  it.todo("single potion (plain, newcomer first contract)");

  // Components and blocks
  it.todo("single rune component (newcomer first contract)");
  it.todo("two runes (no block)");
  it.todo("three alike runes form a block (60 G base)");
  it.todo("four runes (no block, 100 G base)");
  it.todo("three runes + three moonstones form two separate blocks");

  // Cursed and high-enchantment surcharges (item-scope)
  it.todo("cursed sword adds 50% surcharge on the item base premium");
  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge");
  it.todo("cursed and highly enchanted sword stacks both surcharges");
  it.todo("policy with cursed sword and plain amulet — surcharge only on cursed item");

  // Customer-level modifiers
  it.todo("loyalty discount 20% for customer with 2+ years");
  it.todo("first insurance surcharge 10% on policy");
  it.todo("follow-up contract 15% discount applied on second quote");

  // Rounding
  it.todo("premium rounded UP in favor of MHPCO");

  // Integration examples from spec
  it.todo("newcomer with cursed sword → premium 165 G");
  it.todo("long-standing customer second contract with cursed enchanted sword → 160 G");

  // Claim — basic
  it.todo("simple claim: damage minus 100 G deductible");
  it.todo("claim on rune (no special clause) yields damage minus deductible");
  it.todo("high-enchantment item (enchantment ≥8) reimbursed at 50%, then deductible");
  it.todo("dragon-material item fully reimbursed, then deductible");
  it.todo("dragon-material + high enchantment → 50% rule wins, then deductible");

  // Claim — multiple damages and cap
  it.todo("multiple damaged items — deductible applied per damage event");
  it.todo("cap = 2 × insurance sum; multi-claim cap exhaustion across two claims");
  it.todo("payout rounded DOWN");

  // Error cases
  it.todo("unknown item type in quote → throws / exits non-zero");
  it.todo("claim references item type not in policy → throws");
  it.todo("claim with negative damage amount → throws");
  it.todo("claim with more damage entries of a type than insured → throws");
});

